insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('ccd88b84-14e7-4117-8141-718534b39ed9', '5e9e33b8-774e-4232-842f-b190548d1273', $$DCDA — structuurformule (figuur 1)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-context1.png$$,
   $$Dicyaandiamide (DCDA, zie figuur 1) is een wit kristallijn poeder. Het is onder andere een bouwsteen in de synthese van medicijnen. figuur 1: structuurformule van DCDA — een centraal C-atoom met een NH₂-groep, dubbel gebonden aan een N-atoom dat verder verbonden is met een nitrilgroep (C≡N), en enkel gebonden aan een tweede NH₂-groep (H₂N-).$$, 'inline'),
  ('0954f564-cb83-4b21-a9e0-65f559bf8156', '5e9e33b8-774e-4232-842f-b190548d1273', $$figuur 2 — blokschema productieproces DCDA (R1, S1, R2, S2)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-context2.png$$,
   $$In figuur 2 is het industriële productieproces van DCDA vereenvoudigd met een blokschema weergegeven. Calciumcyaanamide (CaCN₂), water en koolstofdioxide worden reactor 1 (R1) ingeleid. Calciumcyaanamide is een sterke base. In R1 reageren calciumcyaanamide, koolstofdioxide en een overmaat water tot het zwakke zuur cyaanamide (H₂N–C≡N) en de vaste stof X. Stof X wordt in scheidingsruimte 1 (S1) verwijderd, waarbij het mengsel in S1 op kamertemperatuur wordt gehouden. figuur 2: blokschema van het DCDA-proces — R1 (in: CaCN₂, H₂O, CO₂; uit: stof X en H₂N–C≡N opgelost in water) → S1 (stof X wordt afgescheiden; de cyaanamide-oplossing gaat door) → R2 (in: CaO; uit: DCDA en Ca(OH)₂ opgelost in water) → S2 (DCDA wordt afgescheiden; H₂O en Ca(OH)₂ gaan terug).$$, 'inline'),
  ('9eb16460-0c02-456f-b53d-509e4b2e78e3', '5e9e33b8-774e-4232-842f-b190548d1273', $$Kz en concentratie van de cyaanamide-oplossing$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-context3.png$$,
   $$De waarde van de Kz van cyaanamide is 5,42·10⁻¹¹. De concentratie van de cyaanamide-oplossing die R1 verlaat, is 250 g L⁻¹.$$, 'inline'),
  ('acb3de07-270a-44dc-8510-2c3702198ebc', '5e9e33b8-774e-4232-842f-b190548d1273', $$dimerisatie van cyaanamide tot DCDA in R2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-context4.png$$,
   $$DCDA is een dimeer van cyaanamide. In reactor 2 (R2) reageert cyaanamide door een dimerisatie-reactie tot DCDA. Bij de dimerisatie van cyaanamide treedt het stikstofatoom in de NH₂-groep van cyaanamide op als nucleofiel deeltje. Cyaanamide is een amfolyt. Dat betekent dat de stof ook als base kan reageren. Als de pH te laag is, neemt de NH₂-groep van cyaanamide een H⁺-ion op. De gevormde groep kan dan niet meer als nucleofiel deeltje reageren en daardoor kan geen dimerisatie van cyaanamide tot DCDA meer plaatsvinden. Na de reactie laat men DCDA in scheidingsruimte 2 (S2) uitkristalliseren en wordt DCDA als vaste stof afgescheiden.$$, 'inline'),
  ('7e63e923-81b0-4c5a-9123-c06ff09ec858', '5e9e33b8-774e-4232-842f-b190548d1273', $$figuur 3 — structuurisomerisatie-evenwicht van DCDA$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-context5.png$$,
   $$In oplossingen van DCDA treedt omkeerbare structuurisomerisatie op. Dit evenwicht is weergegeven in figuur 3. figuur 3: evenwicht tussen twee structuurisomeren van DCDA. Links H₂N-C(=N-C≡N)-NH₂ (de NH aan de ringstikstof zit als dubbele binding met de linker C, en de rechter C≡N hangt aan die stikstof); rechts de andere isomeer H₂N-C(=NH)-N(H)-C≡N, waarbij het NH nu als dubbele binding aan de andere kant zit en de N tussen de twee C-atomen een extra H draagt.$$, 'inline'),
  ('9e71bf06-cc12-450c-920d-e57f883fba99', '5e9e33b8-774e-4232-842f-b190548d1273', $$massaspectrum van DCDA — fragment-ionen bij m/z = 43 en m/z = 68$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-context6.png$$,
   $$Het is onmogelijk om een van de twee structuurisomeren zuiver te verkrijgen. In het massaspectrum van DCDA zijn daarom fragment-ionen van beide isomeren herkenbaar. Behalve de piek van het molecuul-ion (M⁺) zijn twee kenmerkende pieken aanwezig: bij m/z = 43 bevindt zich een piek die maar van één structuurisomeer afkomstig kan zijn; bij m/z = 68 bevindt zich een piek die van beide structuurisomeren afkomstig kan zijn. De fragment-ionen worden gevormd doordat in het molecuul-ion slechts één enkele binding wordt verbroken. Op de uitwerkbijlage is figuur 3 twee keer weergegeven.$$, 'inline'),
  ('7e797f51-7def-47ff-98d4-2cd49bafffd8', '5e9e33b8-774e-4232-842f-b190548d1273', $$uitwerkbijlage vraag 5 — figuur 3 twee keer (a en b)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-context7.png$$,
   $$uitwerkbijlage bij vraag 5: figuur 3 (het isomerisatie-evenwicht van DCDA) is twee keer afgedrukt, gemerkt met a en b. Bij a moet in de juiste isomeer het fragment omcirkeld worden dat de piek bij m/z = 43 veroorzaakt; bij b moet in elke isomeer het fragment omcirkeld worden dat een piek bij m/z = 68 veroorzaakt.$$, 'uitwerkbijlage'),
  ('eb8f7af3-8b60-4573-8488-3368f790b6fa', '5e9e33b8-774e-4232-842f-b190548d1273', $$figuur 4 — metformine, gesynthetiseerd uit DCDA$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-context8.png$$,
   $$DCDA dient onder andere als beginstof voor de synthese van metformine. Zie figuur 4. Metformine wordt vooral voorgeschreven als medicijn bij de behandeling van diabetes mellitus type 2 (suikerziekte). Metformine kan met behulp van een bepaald reactietype in één stap worden gemaakt uit DCDA en één andere beginstof. In deze reactie is metformine het enige product. figuur 4: structuurformule van metformine — H₂N-C(=NH)-NH-C(=NH)-N(CH₃)₂.$$, 'inline'),
  ('672dd455-0bcf-4e21-a619-5bc14005ef43', '5a992061-7eeb-4900-bcb6-f7f611989360', $$bacteriële omzetting van sacharose tot melkzuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-context1.png$$,
   $$Veel mensen krijgen er vroeg of laat in hun leven mee te maken: een gaatje in een kies of tand. Gaatjes worden veroorzaakt door bacteriën in tandplak die suikers uit voeding omzetten tot zuren, waardoor de pH in de tandplak daalt. Een voorbeeld van zo'n bacteriële omzetting is de reactie van sacharose met één andere stof tot 2-hydroxypropaanzuur. Hierbij is 2-hydroxypropaanzuur het enige reactieproduct.$$, 'inline'),
  ('209cec48-e23a-466a-895d-faa5b5d33c2f', '5a992061-7eeb-4900-bcb6-f7f611989360', $$figuur 1 — evenwicht demineralisatie/remineralisatie van tandglazuur (HA)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-context2.png$$,
   $$Tandglazuur bestaat voor 95% uit calciumhydroxyapatiet (HA) en kan worden weergegeven met de formule Ca₅(PO₄)₃OH. In de mond staat het oppervlak van het tandglazuur continu in contact met tandplak en speeksel, waarbij ionen worden uitgewisseld. In figuur 1 is deze uitwisseling weergegeven als een evenwicht. figuur 1: Ca₅(PO₄)₃OH (tandglazuur) ⇌ 5 Ca²⁺ + 3 PO₄³⁻ + OH⁻ (in speeksel); naar rechts heet demineralisatie, naar links remineralisatie.$$, 'inline'),
  ('f0cb80a4-bd1d-45b8-93f0-741df6f5aa78', '5a992061-7eeb-4900-bcb6-f7f611989360', $$demineralisatie/remineralisatie afhankelijk van pH (drempel 5,5)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-context3.png$$,
   $$Als de pH in tandplak door de zuurproductie van bacteriën daalt tot 5,5 of lager, lost tandglazuur deels op, waardoor een gaatje kan ontstaan. Dit oplossen heet demineralisatie. Speeksel kan ervoor zorgen dat de pH weer hoger wordt dan 5,5, waardoor remineralisatie optreedt. Hierdoor kan een beginnend gaatje worden hersteld. Remineralisatie gebeurt ook als bacteriën in de tandplak niet meer voldoende suikers kunnen omzetten.$$, 'inline'),
  ('df57e10c-c0ae-4d09-a582-368d1acbbeee', '5a992061-7eeb-4900-bcb6-f7f611989360', $$fluoridetandpasta zet HA om in calciumfluor-apatiet (FA)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-context4.png$$,
   $$Door goed te poetsen en te flossen wordt tandplak verwijderd en kunnen gaatjes worden tegengegaan. Tandpasta met fluoride beschermt het glazuur nog beter tegen tandbederf. Fluoride-ionen in de tandpasta worden namelijk uitgewisseld met hydroxide-ionen in HA. HA wordt zo omgezet tot calciumfluor-apatiet (FA): Ca₅(PO₄)₃F.$$, 'inline'),
  ('b0d35a3f-94cb-400e-bab1-2918fc447ee2', '5a992061-7eeb-4900-bcb6-f7f611989360', $$demineralisatiedrempel van FA (pH 4,5) en fluoridebehandeling$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-context5.png$$,
   $$De demineralisatie van FA is vergelijkbaar met die van HA (figuur 1). De pH-waarde waarbij demineralisatie optreedt bij FA is 4,5 of lager. Bij kinderen wordt soms een fluoridebehandeling toegepast. Hierbij komt het tandglazuur enige tijd in aanraking met een hoge concentratie fluoride-ionen en wordt HA omgezet tot FA.$$, 'inline'),
  ('abf19557-7b29-4391-887b-d2a339f29e43', '5a992061-7eeb-4900-bcb6-f7f611989360', $$figuur 2 — BisGMA, monomeer voor tandkleurige composieten$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-context6.png$$,
   $$Bij het vullen van gaatjes wordt als vulmateriaal steeds vaker gekozen voor tandkleurige composieten. In deze composieten zijn onder andere additiepolymeren verwerkt. De polymeren zijn zo gekozen dat tijdens het uitharden van het vulmateriaal in de mond een driedimensionaal polymeernetwerk ontstaat. Een veelgebruikt monomeer voor dergelijke polymeren is BisGMA. In figuur 2 is de structuurformule van BisGMA vereenvoudigd weergegeven. De letter R stelt hier een atoomgroep voor die niet aan de polymerisatiereactie kan deelnemen. figuur 2: BisGMA — twee CH₂=C(CH₃)-C(=O)-O- eenheden, elk verbonden via een esterzuurstof aan een centrale groep R (R = C₂₁H₂₆O₄), zodat het molecuul aan beide uiteinden een polymeriseerbare C=C-groep heeft.$$, 'inline'),
  ('f49eba07-22f0-48bf-a58e-09313ecf0598', '5a992061-7eeb-4900-bcb6-f7f611989360', $$figuur 3 — kamferquinon, initiator in het composietmengsel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-context7.png$$,
   $$Als een diep gaatje gevuld moet worden, dan moet het composietmengsel laag voor laag worden aangebracht. In het composietmengsel zit ook een initiator. Een veelgebruikte initiator is kamferquinon (figuur 3). Een aantal C-atomen in kamferquinon zijn genummerd. figuur 3: structuurformule van kamferquinon, een bicyclisch molecuul met twee naast elkaar liggende C=O-groepen (C1 en C2) in de ring en twee methylgroepen (CH₃) op een brugkoolstofatoom (C7).$$, 'inline'),
  ('08b984ec-552e-4099-8a50-21fbdf9705db', '5a992061-7eeb-4900-bcb6-f7f611989360', $$belichting activeert de polymerisatie per laag$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-context8.png$$,
   $$Bij het opvullen van een gaatje wordt elke aangebrachte laag beschenen met een lampje. Daarna pas start de polymerisatie van deze laag en hardt de laag uit.$$, 'inline'),
  ('1861f780-7726-4406-9121-ef44070fe8e2', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$figuur 1 — aniline en het Béchamp-proces$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context1.png$$,
   $$Aniline (figuur 1) behoort tot de meest geproduceerde stoffen in de chemische industrie. Het wordt gebruikt als grondstof voor veel synthetische kleurstoffen en kunststoffen. Ruim 100 jaar geleden werd aniline industrieel geproduceerd met het Béchamp-proces: in enkele stappen reageert nitrobenzeen (C₆H₅NO₂) met ijzer en water tot aniline en Fe₃O₄. figuur 1: structuurformule van aniline — een benzeenring met een NH₂-groep.$$, 'inline'),
  ('757da83d-b2d2-475b-94b7-3a92436e9371', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$Fe3O4 is een dubbelzout met Fe2+ en Fe3+$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context2.png$$,
   $$Het Béchamp-proces wordt niet meer ingezet voor de productie van aniline, maar wel voor de productie van Fe₃O₄, dat als zwart pigment wordt gebruikt. Fe₃O₄ is een dubbelzout. In Fe₃O₄ komen zowel Fe²⁺-ionen als Fe³⁺-ionen voor.$$, 'inline'),
  ('99bc87bb-757f-4d26-98f8-a46754bee314', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$moderne productieprocessen: nitrobenzeen-proces en fenol-proces$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context3.png$$,
   $$Tegenwoordig wordt vrijwel alle aniline geproduceerd met een van de volgende processen: het nitrobenzeen-proces, gebaseerd op de reactie van nitrobenzeen met waterstof; het fenol-proces, gebaseerd op de reactie tussen fenol en ammoniak. Beide processen worden commercieel uitgevoerd in de gasfase en in de vloeibare fase.$$, 'inline'),
  ('61fc943b-deef-4d38-b8e9-fc50b7c1f976', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$nitrobenzeen-proces — reactie 1 in R1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context4.png$$,
   $$nitrobenzeen-proces. Op de uitwerkbijlage bij vraag 16 is het blokschema van het nitrobenzeen-proces onvolledig weergegeven. In reactor 1 (R1) verloopt reactie 1: C₆H₅NO₂ (g) + 3 H₂ (g) ⇌ C₆H₅NH₂ (g) + 2 H₂O (g) (reactie 1).$$, 'inline'),
  ('16e16394-fb4d-4cd5-a8e2-5a45a89bd2a2', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$scheiding in S1, S2, S3 op basis van kookpunt$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context5.png$$,
   $$In scheidingsruimte 1 (S1) wordt de temperatuur zo ingesteld dat een van de stoffen S1 verlaat in de gasfase. De andere stoffen verlaten S1 als vloeibaar mengsel. In de volgende scheidingsruimtes (S2 en S3) wordt het overgebleven mengsel gedestilleerd. De temperaturen in S2 en S3 zijn steeds zo gekozen dat slechts één stof de ruimte in de gasfase kan verlaten.$$, 'inline'),
  ('7d8b19f0-e6c7-42c3-98c5-262c04048280', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$temperatuurverhoging verschuift evenwicht R1 naar links$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context6.png$$,
   $$Voor een constante productkwaliteit moet de temperatuur in R1 gelijk blijven tijdens het proces. Dit doet men door te koelen. Er komt namelijk warmte vrij tijdens reactie 1. Door de temperatuur in de reactor te variëren, wordt het nitrobenzeen-proces geoptimaliseerd. Hierbij wordt gestreefd naar een hoge opbrengst van aniline in een zo kort mogelijke tijd. Bij verhoging van de temperatuur verschuift het evenwicht in R1 naar links. Dit verschuiven hoeft niet nadelig te zijn voor de opbrengst.$$, 'inline'),
  ('5b8d8e10-37d6-4944-bc20-da75d9a71d21', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$fenol-proces — reactie 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context7.png$$,
   $$fenol-proces. Bij het fenol-proces wordt een overmaat ammoniak gemengd met fenol. In dit proces verloopt reactie 2: C₆H₅OH + NH₃ ⇌ C₆H₅NH₂ + H₂O (reactie 2).$$, 'inline'),
  ('e4622252-f34c-4a91-8b40-1fca134a1043', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$rendement fenol-proces is lager dan 100% door nevenproducten$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context8.png$$,
   $$Omdat een deel van het gebruikte fenol reageert tot nevenproducten, is het rendement lager dan 100%.$$, 'inline'),
  ('81132c5b-81f4-42de-8d9b-f15e4325c120', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$tabel — vormingswarmte en kookpunt van nitrobenzeen, fenol en aniline$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context9.png$$,
   $$informatie bij vragen 16, 17 en 19 — eigenschappen van nitrobenzeen, fenol en aniline: tabel met vormingswarmte (kJ mol⁻¹) en kookpunt (K). nitrobenzeen (l): 12,50 kJ mol⁻¹, 484 K; nitrobenzeen (g): 68,53 kJ mol⁻¹; fenol (l): –106,3 kJ mol⁻¹, 455 K; fenol (g): –96,44 kJ mol⁻¹; aniline (l): 31,3 kJ mol⁻¹, 457 K; aniline (g): 87,03 kJ mol⁻¹.$$, 'inline'),
  ('64ec63ca-50e8-4a3a-a275-2ac3acb25bc9', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$tabel — E-factor, atoomeconomie en rendement van drie productieprocessen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context10.png$$,
   $$kenmerken van drie productieprocessen van aniline: tabel met E-factor, atoomeconomie en rendement. Béchamp-proces: atoomeconomie 100%, rendement 100% (E-factor niet gegeven); nitrobenzeen-proces: E-factor 0,40, atoomeconomie 72,1%, rendement 99%; fenol-proces: E-factor 0,39, atoomeconomie 83,7% (rendement niet gegeven — dit is de gevraagde waarde bij vraag 19).$$, 'inline'),
  ('a5799d50-f8e0-47dc-b819-52c5ea097c9c', '54adc283-ef4d-47e1-926c-9b2000cb6424', $$uitwerkbijlage vraag 16 — onvolledig blokschema nitrobenzeen-proces$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-aniline-context11.png$$,
   $$uitwerkbijlage bij vraag 16: onvolledig blokschema van het nitrobenzeen-proces. Instroom H₂ en nitrobenzeen naar reactor R1; R1 met een uitgaande stofstroom (aangeduid met *) naar scheidingsruimte S1; S1 (rechthoekig, temperatuur T < ...... K) met een ontbrekende uitgaande stroom naar boven en een stroom (*) naar S2; S2 (ovaal, T < ...... K) met een ontbrekende uitgaande stroom naar boven en een stroom (*) naar S3; S3 (ovaal, T < ...... K) met een ontbrekende uitgaande stroom naar boven en de eindstroom naar rechts. De kandidaat moet in S1, S2 en S3 de maximale temperatuur invullen en bij elke pijl de naam van de stof noteren.$$, 'uitwerkbijlage'),
  ('10e60aff-9b90-4eef-89b7-9c6e4048326c', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$figuur 1 — felinine en uitscheidingsgegevens$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context1.png$$,
   $$Urine van katers (kater-urine) heeft een penetrante en onprettige geur. Dat komt door de afbraakproducten van het aminozuur felinine (figuur 1). Katers ouder dan drie maanden hebben in hun urine een hoog gehalte van het aminozuur felinine. Bij poezen is dat gehalte een stuk lager. Een volwassen kater plast gemiddeld drie keer per dag, en per keer gemiddeld 30 mL urine. Per dag scheidt een volwassen kater gemiddeld 122 µmol felinine per kilogram lichaamsgewicht uit. figuur 1: structuurformule van felinine — HO-C(=O)-CH(NH₂)-CH₂-S-C(CH₃)₂-CH₂-CH₂-OH.$$, 'inline'),
  ('f2213405-5715-4e69-820f-859a67f35d9b', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$katten scheiden relatief veel eiwitten/aminozuren uit via urine (cauxine)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context2.png$$,
   $$De meeste gezonde zoogdieren scheiden weinig eiwitten en aminozuren uit via de urine, om zo kostbare bouwstoffen te behouden. Katten zijn hierop een uitzondering. Katten-urine bevat behalve felinine ook een relatief hoog gehalte aan het enzym cauxine. Cauxine is een zogeheten carboxyl-esterase. De meeste zoogdieren hebben andere carboxyl-esterases, die niet via de urine worden uitgescheiden. Dit type enzym wordt hieronder 'normale' carboxyl-esterase genoemd.$$, 'inline'),
  ('1b3f6025-2939-4a09-a881-a9805d9b86c3', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$aminozuurcodering: ~DEL (normaal) versus DNA-streng van cauxine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context3.png$$,
   $$Het fragment van het uiteinde van de aminozuurketen in 'normale' carboxyl-esterase kan worden weergegeven door ~DEL. In deze codering is elk aminozuur weergegeven met het 1-lettersymbool. Cauxine is een relatief klein carboxyl-esterase en heeft andere aminozuren aan het uiteinde dan 'normale' carboxyl-esterase. Het stukje van de coderende streng van het DNA dat codeert voor de laatste drie aminozuren van cauxine, is: ~ ATT GTC CCC.$$, 'inline'),
  ('cd97c085-da17-4486-b02a-d5b0cedde3cf', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$figuur 2 — vorming van felinine uit MBG via MBCG (stap 1 en stap 2)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context4.png$$,
   $$Felinine wordt in het lichaam van katten door hydrolyse gevormd uit MBG. In figuur 2 zijn de betrokken omzettingen vereenvoudigd weergegeven. figuur 2: stap 1: MBG (een tripeptide-achtige verbinding opgebouwd uit glutaminezuur, een cysteïne-eenheid met een S-C(CH₃)₂-CH₂-CH₂-OH-zijgroep, en glycine) + ... → MBCG + glutaminezuur (hydrolyse, glutaminezuur wordt afgesplitst); stap 2: MBCG + ... → felinine + glycine (hydrolyse, glycine wordt afgesplitst).$$, 'inline'),
  ('795278cd-4077-4111-ae1b-74bacc1bf36b', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$reactievergelijking van stap 1 op de uitwerkbijlage$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context5.png$$,
   $$Op de uitwerkbijlage is de reactievergelijking van stap 1 nogmaals weergegeven.$$, 'inline'),
  ('66338e24-c86a-426b-a71b-f783c63e3b7b', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$figuur 3 — dunnelaagchromatografie van MBG/MBCG met/zonder cauxine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context6.png$$,
   $$Met behulp van dunnelaag-chromatografie is onderzocht of het enzym cauxine een rol speelt bij de omzettingen in figuur 2. Hiertoe zijn de volgende zes oplossingen bereid: a en b: MBG zonder en met cauxine; c en d: MBCG zonder en met cauxine; e: glycine; f: felinine. Na een reactietijd van 10 uur bij 38 °C (voor oplossingen a tot en met d) werd van alle oplossingen een chromatogram gemaakt. De resultaten zijn in figuur 3 weergegeven. Cauxine is op deze chromatogrammen niet zichtbaar. figuur 3: chromatogram met banen a (MBG zonder cauxine: 1 vlek laag), b (MBG met cauxine: 1 vlek op dezelfde hoogte als a, geen verandering), c (MBCG zonder cauxine: 1 vlek hoger), d (MBCG met cauxine: 2 vlekken — één op dezelfde hoogte als c, en één nieuwe vlek op dezelfde hoogte als baan e), e (glycine: 1 vlek), f (felinine: 1 vlek, hoog).$$, 'inline'),
  ('a3e3d905-8a4c-49a9-a594-b089f8be1d66', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$twee hypothesen over de rol van cauxine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context7.png$$,
   $$De onderzochte hypothesen zijn: Hypothese 1: Cauxine is betrokken bij de omzetting van MBG tot MBCG (stap 1). Hypothese 2: Cauxine is betrokken bij de omzetting van MBCG tot felinine (stap 2).$$, 'inline'),
  ('86b82ef4-437f-487d-a3a9-ebd21a363c3c', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$figuur 4 — afbraakproducten X en Y van felinine in de bodem$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context8.png$$,
   $$Felinine heeft van zichzelf weinig geur. Nadat felinine via de urine in de bodem terecht is gekomen, wordt dit onder andere door micro-organismen omgezet tot een reeks verschillende stoffen die wel een geur hebben, zoals de stoffen X en Y. Zie figuur 4. figuur 4: structuurformules van stof X (HS-C(CH₃)₂-CH₂-CH₂-OH) en stof Y (CH₃-S-C(CH₃)₂-CH₂-CH₂-OH).$$, 'inline'),
  ('0c29c6a4-4fe7-40a5-8fb2-8d26d93d4d10', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$figuur 5 — piekoppervlaktes van X en Y in bodemmonsters (GK, P, JK, NGK)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context9.png$$,
   $$Uit onderzoek met bodemmonsters met katten-urine blijkt dat de stoffen X en Y ook in de bodem voorkomen als gecastreerde katers (GK), poezen (P) en jonge katers (JK) hebben geürineerd. Er zijn ook bodemmonsters onderzocht met urine van niet-gecastreerde katers (NGK). De geur van deze bodemmonsters is veel intenser dan die van de monsters van GK, P en JK. Om te bepalen welke stof met name verantwoordelijk is voor de geur, zijn gaschromatogrammen gemaakt van alle monsters. De hoeveelheid urine is in elk monster gelijk. Van de stoffen X en Y zijn vervolgens de piekoppervlaktes bepaald. figuur 5: twee staafdiagrammen van piekoppervlak (·10⁵) voor NGK, GK, P en JK. Stof X: NGK ≈ 700, GK ≈ 125, P ≈ 125, JK ≈ 25. Stof Y: NGK ≈ 11, GK ≈ 5,2, P ≈ 7,5, JK ≈ 3.$$, 'inline'),
  ('2e6fdf2a-e981-4b75-b3c9-be3c9fbd079b', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$stof X geeft bij lagere concentratie al een hogere geurintensiteit dan Y$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context10.png$$,
   $$Van stof X is bekend dat deze stof bij een tien maal zo lage concentratie, een hogere geurintensiteit geeft dan stof Y. Uit figuur 5 kan worden afgeleid dat stof X meer van invloed is op de intensiteit van de geur van kater-urine dan stof Y.$$, 'inline'),
  ('3f7620c0-4ae6-4cd5-8e56-9d0620dbea7f', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$vervolgexperiment: hydrolysesnelheid van MBCG$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context11.png$$,
   $$In een vervolgexperiment is de snelheid van de hydrolyse van MBCG onderzocht in een oplossing met 7,4 g L⁻¹ MBCG. Na een reactietijd van 5,0 minuten bleek MBCG voor 1,20·10⁻² % te zijn omgezet.$$, 'inline'),
  ('b74c04fe-b52e-4717-8408-a3177c0e8427', '31c3a3d2-705a-4de0-a311-43cf55dcb779', $$uitwerkbijlage vraag 23 — reactievergelijking stap 1 (MBG + ... → MBCG + glutaminezuur)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-kater-context12.png$$,
   $$uitwerkbijlage bij vraag 23: de structuurformule van MBG is gegeven (opgebouwd uit glutaminezuur, een cysteïne-eenheid met een S-C(CH₃)₂-CH₂-CH₂-OH-zijgroep, en glycine), gevolgd door '+ …… →' met een leeg vak voor het reactieproduct. Daaronder twee stippellijnen gescheiden door een '+', voor de twee productstructuren (MBCG en glutaminezuur) die de kandidaat moet invullen.$$, 'uitwerkbijlage');

insert into practice_questions (id, exercise_id, question_number, topics, keywords, question_summary, question_image_url, question_text, context_block_ids) values
  ('10ac129a-853e-49b6-9164-746919a79f72', '5e9e33b8-774e-4232-842f-b190548d1273', 1,
   '[{"domain": "Reacties", "subdomain": "Chemische processen"}]'::jsonb,
   '["cyaanamide", "calciumcyaanamide", "calciumcarbonaat", "reactievergelijking opstellen", "zuur-base reactie"]'::jsonb,
   $$Opstellen van de reactievergelijking voor de vorming van cyaanamide uit calciumcyaanamide$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-vraag1.png$$, $$Geef de vergelijking van de reactie die optreedt in R1. Gebruik formules voor alle stoffen en neem aan dat uitsluitend cyaanamide en de vaste stof X ontstaan.$$, array['0954f564-cb83-4b21-a9e0-65f559bf8156']::uuid[]),
  ('087f941c-80d4-4590-96d1-c3e554c14da6', '5e9e33b8-774e-4232-842f-b190548d1273', 2,
   '[{"domain": "Rekenen en analyse", "subdomain": "Scheiding en analyse"}]'::jsonb,
   '["filtreren", "scheidingsmethode", "oplosbaarheid", "vaste stof afscheiden"]'::jsonb,
   $$Bepalen van de juiste scheidingsmethode voor een vaste stof uit een reactiemengsel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-vraag2.png$$, $$Voer de volgende opdrachten uit:
− Geef aan welke scheidingsmethode geschikt is om stof X uit het mengsel in S1 te verwijderen.
− Leg hierbij uit welk verschil in stofeigenschap van cyaanamide en stof X deze scheiding mogelijk maakt.$$, array['0954f564-cb83-4b21-a9e0-65f559bf8156']::uuid[]),
  ('f9a4a59d-42a3-4e08-90f7-82e0706b2bf4', '5e9e33b8-774e-4232-842f-b190548d1273', 3,
   '[{"domain": "Rekenen en analyse", "subdomain": "Grootheden en relaties"}]'::jsonb,
   '["pH berekenen", "zwak zuur", "zuurconstante Kz", "molariteit", "cyaanamide"]'::jsonb,
   $$Berekenen van de pH van een oplossing van een zwak zuur met behulp van Kz$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-vraag3.png$$, $$Bereken de pH van deze cyaanamide-oplossing. Gebruik de Kz. Neem aan dat de pH van de cyaanamide-oplossing uitsluitend wordt bepaald door cyaanamide.$$, array['0954f564-cb83-4b21-a9e0-65f559bf8156', '9eb16460-0c02-456f-b53d-509e4b2e78e3']::uuid[]),
  ('49819547-7d22-4ef5-8920-2f4355007287', '5e9e33b8-774e-4232-842f-b190548d1273', 4,
   '[{"domain": "Materie", "subdomain": "Deeltjesmodellen"}, {"domain": "Reacties", "subdomain": "Reactiekinetiek"}]'::jsonb,
   '["lewisstructuur", "nucleofiel deeltje", "cyaanamide", "protonering", "niet-bindend elektronenpaar"]'::jsonb,
   $$Tekenen van lewisstructuren en verklaren van het verlies van nucleofiel karakter na protonering$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-vraag4.png$$, $$Voer de volgende opdrachten uit:
− Geef de lewisstructuur van cyaanamide en van het deeltje dat ontstaat als cyaanamide een H⁺-ion heeft opgenomen.
− Leg uit dat het stikstofatoom van de NH₂-groep niet meer nucleofiel is als deze groep een H⁺-ion heeft opgenomen.$$, array['0954f564-cb83-4b21-a9e0-65f559bf8156', 'acb3de07-270a-44dc-8510-2c3702198ebc']::uuid[]),
  ('6dec4750-7e84-486e-bb20-11634a4ba2d8', '5e9e33b8-774e-4232-842f-b190548d1273', 5,
   '[{"domain": "Rekenen en analyse", "subdomain": "Scheiding en analyse"}]'::jsonb,
   '["massaspectrometrie", "molecuul-ion", "fragmentatie", "m/z", "structuurisomerie"]'::jsonb,
   $$Identificeren van fragment-ionen in een massaspectrum van twee structuurisomeren$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-vraag5.png$$, $$Voer de volgende opdrachten uit op de uitwerkbijlage:
− Omcirkel bij a in de juiste isomeer het fragment dat de piek bij m/z = 43 veroorzaakt.
− Omcirkel bij b in elke isomeer het fragment dat een piek bij m/z = 68 veroorzaakt.$$, array['7e63e923-81b0-4c5a-9123-c06ff09ec858', '9e71bf06-cc12-450c-920d-e57f883fba99', '7e797f51-7def-47ff-98d4-2cd49bafffd8']::uuid[]),
  ('cb55a3a5-31ae-4103-abda-2b98d01ff1ba', '5e9e33b8-774e-4232-842f-b190548d1273', 6,
   '[{"domain": "Reacties", "subdomain": "Chemische processen"}]'::jsonb,
   '["metformine", "additiereactie", "dimethylamine", "nitrilgroep", "structuurformule tekenen"]'::jsonb,
   $$Bepalen van de tweede beginstof en het reactietype bij de vorming van metformine uit DCDA$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-dcda-vraag6.png$$, $$Voer de volgende opdrachten uit:
− Teken de structuurformule van deze andere beginstof.
− Geef de naam van het reactietype.$$, array['ccd88b84-14e7-4117-8141-718534b39ed9', 'eb8f7af3-8b60-4573-8488-3368f790b6fa']::uuid[]),
  ('76722da4-0a23-4d26-bd40-f68003cbbe02', '5a992061-7eeb-4900-bcb6-f7f611989360', 7,
   '[{"domain": "Reacties", "subdomain": "Chemische processen"}]'::jsonb,
   '["sacharose", "melkzuur", "reactievergelijking opstellen", "hydrolyse", "molecuulformule"]'::jsonb,
   $$Opstellen van de reactievergelijking voor de omzetting van sacharose tot melkzuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-vraag7.png$$, $$Geef de vergelijking van deze omzetting.
− Gebruik molecuulformules.
− Gebruik Binas-tabel 67F2 of ScienceData-tabel 13.1.$$, array['672dd455-0bcf-4e21-a619-5bc14005ef43']::uuid[]),
  ('fe3cb8f9-7306-4251-bf1d-a22691f7fc53', '5a992061-7eeb-4900-bcb6-f7f611989360', 8,
   '[{"domain": "Reacties", "subdomain": "Chemisch evenwicht"}]'::jsonb,
   '["evenwicht", "demineralisatie", "tandglazuur", "hydroxyapatiet", "concentratiebreuk"]'::jsonb,
   $$Verklaren van het ontstaan van gaatjes met behulp van het oplosbaarheidsevenwicht van tandglazuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-vraag8.png$$, $$Leg uit, aan de hand van het evenwicht in figuur 1, hoe gaatjes kunnen ontstaan door de aanwezigheid van zuren.$$, array['209cec48-e23a-466a-895d-faa5b5d33c2f', 'f0cb80a4-bd1d-45b8-93f0-741df6f5aa78']::uuid[]),
  ('01453188-4f2b-43b0-ad79-a853cb7449ec', '5a992061-7eeb-4900-bcb6-f7f611989360', 9,
   '[{"domain": "Reacties", "subdomain": "Chemisch evenwicht"}]'::jsonb,
   '["fluoridebehandeling", "demineralisatie", "calciumfluorapatiet", "pH-gebied", "evenwicht"]'::jsonb,
   $$Bepalen van het pH-gebied waarin een fluoridebehandeling het tandglazuur het beste beschermt$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-vraag9.png$$, $$Leg uit in welk pH-gebied de toepassing van de fluoridebehandeling het meest effectief is:
− in gebied 1: 3,5 < pH ≤ 4,5 of
− in gebied 2: 4,5 < pH ≤ 5,5 of
− in gebied 3: 5,5 < pH < 6,5.$$, array['f0cb80a4-bd1d-45b8-93f0-741df6f5aa78', 'df57e10c-c0ae-4d09-a582-368d1acbbeee', 'b0d35a3f-94cb-400e-bab1-2918fc447ee2']::uuid[]),
  ('2011d058-798e-4bec-b70f-90489c05298a', '5a992061-7eeb-4900-bcb6-f7f611989360', 10,
   '[{"domain": "Reacties", "subdomain": "Reactiekinetiek"}]'::jsonb,
   '["additiepolymerisatie", "BisGMA", "polymeernetwerk", "crosslink", "monomeer"]'::jsonb,
   $$Tekenen van een polymeerfragment en verklaren van netwerkvorming bij additiepolymerisatie van BisGMA$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-vraag10.png$$, $$Voer de volgende opdrachten uit:
− Teken de structuurformule van een fragment uit het midden van één BisGMA-polymeerketen:
  1 Laat hierbij twee BisGMA-eenheden met elkaar koppelen.
  2 Gebruik in de BisGMA-eenheden de letter R.
− Leg uit hoe tijdens de polymerisatie van BisGMA een netwerk kan ontstaan.$$, array['abf19557-7b29-4391-887b-d2a339f29e43']::uuid[]),
  ('3ca2bbda-f0e7-4556-aece-7190f74265aa', '5a992061-7eeb-4900-bcb6-f7f611989360', 11,
   '[{"domain": "Materie", "subdomain": "Deeltjesmodellen"}]'::jsonb,
   '["spiegelbeeldisomerie", "chiraal koolstofatoom", "enantiomeren", "kamferquinon"]'::jsonb,
   $$Bepalen of kamferquinon spiegelbeeldisomeren (enantiomeren) heeft$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-vraag11.png$$, $$Leg uit of er van kamferquinon spiegelbeeldisomeren bestaan. Gebruik figuur 3.$$, array['f49eba07-22f0-48bf-a58e-09313ecf0598']::uuid[]),
  ('02226e31-50fd-43fe-aac0-5680c8fd9250', '5a992061-7eeb-4900-bcb6-f7f611989360', 12,
   '[{"domain": "Reacties", "subdomain": "Reactiekinetiek"}]'::jsonb,
   '["fotoinitiator", "radicaal", "initiatie", "polymerisatie starten", "lichtenergie"]'::jsonb,
   $$Verklaren waarom belichting nodig is om de polymerisatie van het composietmengsel te starten$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2025-ii-gaatjes-vraag12.png$$, $$Leg uit waarom de polymerisatie pas start na het beschijnen van het composietmengsel met het lampje.$$, array['f49eba07-22f0-48bf-a58e-09313ecf0598', '08b984ec-552e-4099-8a50-21fbdf9705db']::uuid[]),
  ('e9b0686a-eb01-4c19-a9bf-76a3b0d99f33', '54adc283-ef4d-47e1-926c-9b2000cb6424', 13,
   '[{"domain": "Materie", "subdomain": "Deeltjesmodellen"}]'::jsonb,
   '["IUPAC-naam", "aniline", "aminobenzeen", "systematische naam"]'::jsonb,
